  1→// Package main implements an MCP (Model Context Protocol) server that exposes
  2→// the Aileron control plane as tools callable by Claude Code and other MCP clients.
  3→//
  4→// It communicates over stdio using JSON-RPC 2.0, per the MCP specification.
  5→package main
  6→
  7→import (
  8→	"bufio"
  9→	"context"
 10→	"encoding/json"
 11→	"fmt"
 12→	"os"
 13→
 14→	aileron "github.com/ALRubinger/aileron/sdk/go"
 15→)
 16→
 17→// --- JSON-RPC types ---
 18→
 19→type jsonrpcRequest struct {
 20→	JSONRPC string          `json:"jsonrpc"`
 21→	ID      json.RawMessage `json:"id,omitempty"`
 22→	Method  string          `json:"method"`
 23→	Params  json.RawMessage `json:"params,omitempty"`
 24→}
 25→
 26→type jsonrpcResponse struct {
 27→	JSONRPC string          `json:"jsonrpc"`
 28→	ID      json.RawMessage `json:"id,omitempty"`
 29→	Result  any             `json:"result,omitempty"`
 30→	Error   *jsonrpcError   `json:"error,omitempty"`
 31→}
 32→
 33→type jsonrpcError struct {
 34→	Code    int    `json:"code"`
 35→	Message string `json:"message"`
 36→}
 37→
 38→// --- MCP types ---
 39→
 40→type toolDef struct {
 41→	Name        string    `json:"name"`
 42→	Description string    `json:"description"`
 43→	InputSchema schema    `json:"inputSchema"`
 44→}
 45→
 46→type schema struct {
 47→	Type       string                `json:"type"`
 48→	Properties map[string]schemaProp `json:"properties,omitempty"`
 49→	Required   []string              `json:"required,omitempty"`
 50→}
 51→
 52→type schemaProp struct {
 53→	Type        string `json:"type"`
 54→	Description string `json:"description"`
 55→}
 56→
 57→type callToolParams struct {
 58→	Name      string         `json:"name"`
 59→	Arguments map[string]any `json:"arguments"`
 60→}
 61→
 62→type toolResult struct {
 63→	Content []toolContent `json:"content"`
 64→	IsError bool          `json:"isError,omitempty"`
 65→}
 66→
 67→type toolContent struct {
 68→	Type string `json:"type"`
 69→	Text string `json:"text"`
 70→}
 71→
 72→// --- Server ---
 73→
 74→type server struct {
 75→	client *aileron.Client
 76→}
 77→
 78→func main() {
 79→	apiURL := os.Getenv("AILERON_API_URL")
 80→	if apiURL == "" {
 81→		apiURL = "http://localhost:8080"
 82→	}
 83→	apiKey := os.Getenv("AILERON_API_KEY")
 84→
 85→	client := aileron.NewClient(apiURL, aileron.WithAPIKey(apiKey))
 86→	s := &server{client: client}
 87→
 88→	scanner := bufio.NewScanner(os.Stdin)
 89→	// Increase buffer size for large messages.
 90→	scanner.Buffer(make([]byte, 0, 1024*1024), 1024*1024)
 91→
 92→	for scanner.Scan() {
 93→		line := scanner.Bytes()
 94→		if len(line) == 0 {
 95→			continue
 96→		}
 97→
 98→		var req jsonrpcRequest
 99→		if err := json.Unmarshal(line, &req); err != nil {
100→			continue
101→		}
102→
103→		resp := s.handle(req)
104→		if resp != nil {
105→			data, _ := json.Marshal(resp)
106→			fmt.Fprintf(os.Stdout, "%s\n", data)
107→		}
108→	}
109→}
110→
111→func (s *server) handle(req jsonrpcRequest) *jsonrpcResponse {
112→	switch req.Method {
113→	case "initialize":
114→		return &jsonrpcResponse{
115→			JSONRPC: "2.0",
116→			ID:      req.ID,
117→			Result: map[string]any{
118→				"protocolVersion": "2024-11-05",
119→				"capabilities": map[string]any{
120→					"tools": map[string]any{},
121→				},
122→				"serverInfo": map[string]any{
123→					"name":    "aileron",
124→					"version": "0.0.1",
125→				},
126→			},
127→		}
128→
129→	case "notifications/initialized":
130→		return nil // no response for notifications
131→
132→	case "tools/list":
133→		return &jsonrpcResponse{
134→			JSONRPC: "2.0",
135→			ID:      req.ID,
136→			Result: map[string]any{
137→				"tools": s.tools(),
138→			},
139→		}
140→
141→	case "tools/call":
142→		var params callToolParams
143→		if err := json.Unmarshal(req.Params, &params); err != nil {
144→			return errorResponse(req.ID, -32602, "invalid params: "+err.Error())
145→		}
146→		result := s.callTool(params)
147→		return &jsonrpcResponse{
148→			JSONRPC: "2.0",
149→			ID:      req.ID,
150→			Result:  result,
151→		}
152→
153→	case "ping":
154→		return &jsonrpcResponse{
155→			JSONRPC: "2.0",
156→			ID:      req.ID,
157→			Result:  map[string]any{},
158→		}
159→
160→	default:
161→		return errorResponse(req.ID, -32601, "method not found: "+req.Method)
162→	}
163→}
164→
165→func (s *server) tools() []toolDef {
166→	return []toolDef{
167→		{
168→			Name:        "submit_intent",
169→			Description: "Submit an action intent to the Aileron control plane for policy evaluation. Returns the disposition (allow/deny/require_approval) and any grant or approval IDs.",
170→			InputSchema: schema{
171→				Type: "object",
172→				Properties: map[string]schemaProp{
173→					"action_type":  {Type: "string", Description: "Dot-namespaced action type, e.g. 'git.pull_request.create', 'payment.charge'"},
174→					"summary":      {Type: "string", Description: "Human-readable summary of what the agent wants to do"},
175→					"justification": {Type: "string", Description: "Why this action is needed"},
176→					"repository":   {Type: "string", Description: "For git actions: owner/repo (e.g. 'acme/checkout')"},
177→					"branch":       {Type: "string", Description: "For git actions: source/head branch"},
178→					"base_branch":  {Type: "string", Description: "For git actions: target/base branch"},
179→					"pr_title":     {Type: "string", Description: "For git PR actions: pull request title"},
180→					"pr_body":      {Type: "string", Description: "For git PR actions: pull request body"},
181→					"workspace_id": {Type: "string", Description: "Workspace ID (default: 'default')"},
182→				},
183→				Required: []string{"action_type", "summary"},
184→			},
185→		},
186→		{
187→			Name:        "check_approval",
188→			Description: "Check the status of a pending approval request. Returns the current status and, if approved, the execution grant ID.",
189→			InputSchema: schema{
190→				Type: "object",
191→				Properties: map[string]schemaProp{
192→					"approval_id": {Type: "string", Description: "The approval ID to check"},
193→				},
194→				Required: []string{"approval_id"},
195→			},
196→		},
197→		{
198→			Name:        "execute_action",
199→			Description: "Execute an approved action using an execution grant. The grant must be active and not expired.",
200→			InputSchema: schema{
201→				Type: "object",
202→				Properties: map[string]schemaProp{
203→					"grant_id": {Type: "string", Description: "The execution grant ID"},
204→				},
205→				Required: []string{"grant_id"},
206→			},
207→		},
208→		{
209→			Name:        "list_pending_approvals",
210→			Description: "List all pending approval requests in the workspace.",
211→			InputSchema: schema{
212→				Type: "object",
213→				Properties: map[string]schemaProp{
214→					"workspace_id": {Type: "string", Description: "Workspace ID (default: 'default')"},
215→				},
216→			},
217→		},
218→	}
219→}
220→
221→func (s *server) callTool(params callToolParams) toolResult {
222→	ctx := context.Background()
223→
224→	switch params.Name {
225→	case "submit_intent":
226→		return s.submitIntent(ctx, params.Arguments)
227→	case "check_approval":
228→		return s.checkApproval(ctx, params.Arguments)
229→	case "execute_action":
230→		return s.executeAction(ctx, params.Arguments)
231→	case "list_pending_approvals":
232→		return s.listPendingApprovals(ctx, params.Arguments)
233→	default:
234→		return toolResult{
235→			Content: []toolContent{{Type: "text", Text: "Unknown tool: " + params.Name}},
236→			IsError: true,
237→		}
238→	}
239→}
240→
241→func (s *server) submitIntent(ctx context.Context, args map[string]any) toolResult {
242→	actionType := argStr(args, "action_type")
243→	summary := argStr(args, "summary")
244→	workspaceID := argStr(args, "workspace_id")
245→	if workspaceID == "" {
246→		workspaceID = "default"
247→	}
248→
249→	req := aileron.CreateIntentRequest{
250→		WorkspaceID:    workspaceID,
251→		AgentID:        "claude_code",
252→		IdempotencyKey: fmt.Sprintf("mcp-%s-%d", actionType, os.Getpid()),
253→		Action: aileron.ActionIntent{
254→			Type:    actionType,
255→			Summary: summary,
256→		},
257→		Context: &aileron.IntentContext{
258→			SourcePlatform: strPtr("claude_code"),
259→			UserPresent:    boolPtr(true),
260→		},
261→	}
262→
263→	if just := argStr(args, "justification"); just != "" {
264→		req.Action.Justification = &just
265→	}
266→
267→	// Populate domain-specific fields.
268→	if repo := argStr(args, "repository"); repo != "" {
269→		branch := argStr(args, "branch")
270→		baseBranch := argStr(args, "base_branch")
271→		prTitle := argStr(args, "pr_title")
272→		prBody := argStr(args, "pr_body")
273→		provider := "github"
274→		req.Action.Domain = &aileron.DomainAction{
275→			Git: &aileron.GitAction{
276→				Provider:   &provider,
277→				Repository: &repo,
278→				Branch:     nilIfEmpty(branch),
279→				BaseBranch: nilIfEmpty(baseBranch),
280→				PRTitle:    nilIfEmpty(prTitle),
281→				PRBody:     nilIfEmpty(prBody),
282→			},
283→		}
284→	}
285→
286→	intent, err := s.client.Intents.Create(ctx, req)
287→	if err != nil {
288→		return errorResult("Failed to submit intent: " + err.Error())
289→	}
290→
291→	result := map[string]any{
292→		"intent_id":   intent.IntentID,
293→		"status":      intent.Status,
294→		"disposition": intent.Decision.Disposition,
295→		"risk_level":  intent.Decision.RiskLevel,
296→	}
297→	if intent.Decision.ApprovalID != nil {
298→		result["approval_id"] = *intent.Decision.ApprovalID
299→		result["message"] = fmt.Sprintf("This action requires approval. Approval ID: %s. The user can approve at the Aileron UI.", *intent.Decision.ApprovalID)
300→	}
301→	if intent.Decision.ExecutionGrantID != nil {
302→		result["grant_id"] = *intent.Decision.ExecutionGrantID
303→		result["message"] = "Action approved by policy. Use execute_action with the grant_id to proceed."
304→	}
305→	if intent.Decision.DenialReason != nil {
306→		result["denial_reason"] = *intent.Decision.DenialReason
307→		result["message"] = fmt.Sprintf("Action denied: %s", *intent.Decision.DenialReason)
308→	}
309→
310→	return jsonResult(result)
311→}
312→
313→func (s *server) checkApproval(ctx context.Context, args map[string]any) toolResult {
314→	approvalID := argStr(args, "approval_id")
315→	if approvalID == "" {
316→		return errorResult("approval_id is required")
317→	}
318→
319→	approval, err := s.client.Approvals.Get(ctx, approvalID)
320→	if err != nil {
321→		return errorResult("Failed to get approval: " + err.Error())
322→	}
323→
324→	result := map[string]any{
325→		"approval_id": approval.ApprovalID,
326→		"status":      approval.Status,
327→		"intent_id":   approval.IntentID,
328→	}
329→
330→	switch approval.Status {
331→	case "approved":
332→		// Get the intent to find the grant ID.
333→		intent, err := s.client.Intents.Get(ctx, approval.IntentID)
334→		if err == nil && intent.Decision.ExecutionGrantID != nil {
335→			result["grant_id"] = *intent.Decision.ExecutionGrantID
336→			result["message"] = "Approved! Use execute_action with the grant_id to proceed."
337→		} else {
338→			result["message"] = "Approved, but grant ID not yet available."
339→		}
340→	case "denied":
341→		result["message"] = "The approval request was denied."
342→	case "pending":
343→		result["message"] = "Still waiting for human approval."
344→	default:
345→		result["message"] = "Approval status: " + approval.Status
346→	}
347→
348→	return jsonResult(result)
349→}
350→
351→func (s *server) executeAction(ctx context.Context, args map[string]any) toolResult {
352→	grantID := argStr(args, "grant_id")
353→	if grantID == "" {
354→		return errorResult("grant_id is required")
355→	}
356→
357→	resp, err := s.client.Executions.Run(ctx, aileron.ExecutionRunRequest{
358→		GrantID: grantID,
359→	})
360→	if err != nil {
361→		return errorResult("Failed to execute: " + err.Error())
362→	}
363→
364→	result := map[string]any{
365→		"execution_id": resp.ExecutionID,
366→		"status":       resp.Status,
367→		"message":      "Execution started. ID: " + resp.ExecutionID,
368→	}
369→
370→	// Poll for completion (the execution may complete synchronously).
371→	exec, err := s.client.Executions.Get(ctx, resp.ExecutionID)
372→	if err == nil {
373→		result["status"] = exec.Status
374→		if exec.Output != nil {
375→			result["output"] = *exec.Output
376→		}
377→		if exec.ReceiptRef != nil {
378→			result["receipt_ref"] = *exec.ReceiptRef
379→			result["message"] = "Execution completed. Result: " + *exec.ReceiptRef
380→		}
381→	}
382→
383→	return jsonResult(result)
384→}
385→
386→func (s *server) listPendingApprovals(ctx context.Context, args map[string]any) toolResult {
387→	workspaceID := argStr(args, "workspace_id")
388→	if workspaceID == "" {
389→		workspaceID = "default"
390→	}
391→
392→	resp, err := s.client.Approvals.List(ctx, workspaceID)
393→	if err != nil {
394→		return errorResult("Failed to list approvals: " + err.Error())
395→	}
396→
397→	var pending []map[string]any
398→	for _, a := range resp.Items {
399→		if a.Status == "pending" {
400→			entry := map[string]any{
401→				"approval_id": a.ApprovalID,
402→				"intent_id":   a.IntentID,
403→				"status":      a.Status,
404→				"requested_at": a.RequestedAt.Format("2006-01-02T15:04:05Z"),
405→			}
406→			if a.Rationale != nil {
407→				entry["rationale"] = *a.Rationale
408→			}
409→			pending = append(pending, entry)
410→		}
411→	}
412→
413→	result := map[string]any{
414→		"count":     len(pending),
415→		"approvals": pending,
416→	}
417→	if len(pending) == 0 {
418→		result["message"] = "No pending approvals."
419→	} else {
420→		result["message"] = fmt.Sprintf("%d pending approval(s).", len(pending))
421→	}
422→
423→	return jsonResult(result)
424→}
