426→// --- Helpers ---
427→
428→func argStr(args map[string]any, key string) string {
429→	v, ok := args[key]
430→	if !ok {
431→		return ""
432→	}
433→	s, ok := v.(string)
434→	if !ok {
435→		return ""
436→	}
437→	return s
438→}
439→
440→func strPtr(s string) *string   { return &s }
441→func boolPtr(b bool) *bool      { return &b }
442→
443→func nilIfEmpty(s string) *string {
444→	if s == "" {
445→		return nil
446→	}
447→	return &s
448→}
449→
450→func jsonResult(v any) toolResult {
451→	data, _ := json.MarshalIndent(v, "", "  ")
452→	return toolResult{
453→		Content: []toolContent{{Type: "text", Text: string(data)}},
454→	}
455→}
456→
457→func errorResult(msg string) toolResult {
458→	return toolResult{
459→		Content: []toolContent{{Type: "text", Text: msg}},
460→		IsError: true,
461→	}
462→}
463→
464→func errorResponse(id json.RawMessage, code int, msg string) *jsonrpcResponse {
465→	return &jsonrpcResponse{
466→		JSONRPC: "2.0",
467→		ID:      id,
468→		Error:   &jsonrpcError{Code: code, Message: msg},
469→	}
470→}
