  1→// Package main implements an MCP (Model Context Protocol) server that exposes
  2→// the Aileron control plane as tools callable by Claude Code and other MCP clients.
  3→//
  4→// It communicates over stdio using JSON-RPC 2.0, per the MCP specification.
  5→package main
  6→
  7→import (
  8→	"bufio"
  9→	"context"
 10→	"encoding/json"
 11→	"fmt"
 12→	"os"
 13→
 14→	aileron "github.com/ALRubinger/aileron/sdk/go"
 15→)
 16→
 17→// --- JSON-RPC types ---
 18→
 19→type jsonrpcRequest struct {
 20→	JSONRPC string          `json:"jsonrpc"`
 21→	ID      json.RawMessage `json:"id,omitempty"`
 22→	Method  string          `json:"method"`
 23→	Params  json.RawMessage `json:"params,omitempty"`
 24→}
 25→
 26→type jsonrpcResponse struct {
 27→	JSONRPC string          `json:"jsonrpc"`
 28→	ID      json.RawMessage `json:"id,omitempty"`
 29→	Result  any             `json:"result,omitempty"`
 30→	Error   *jsonrpcError   `json:"error,omitempty"`
 31→}
 32→
 33→type jsonrpcError struct {
 34→	Code    int    `json:"code"`
 35→	Message string `json:"message"`
 36→}
 37→
 38→// --- MCP types ---
 39→
 40→type toolDef struct {
 41→	Name        string    `json:"name"`
 42→	Description string    `json:"description"`
 43→	InputSchema schema    `json:"inputSchema"`
 44→}
 45→
 46→type schema struct {
 47→	Type       string                `json:"type"`
 48→	Properties map[string]schemaProp `json:"properties,omitempty"`
 49→	Required   []string              `json:"required,omitempty"`
 50→}
 51→
 52→type schemaProp struct {
 53→	Type        string `json:"type"`
 54→	Description string `json:"description"`
 55→}
 56→
 57→type callToolParams struct {
 58→	Name      string         `json:"name"`
 59→	Arguments map[string]any `json:"arguments"`
 60→}
 61→
 62→type toolResult struct {
 63→	Content []toolContent `json:"content"`
 64→	IsError bool          `json:"isError,omitempty"`
 65→}
 66→
 67→type toolContent struct {
 68→	Type string `json:"type"`
 69→	Text string `json:"text"`
 70→}
 71→
 72→// --- Server ---
 73→
 74→type server struct {
 75→	client *aileron.Client
 76→}
 77→
 78→func main() {
 79→	apiURL := os.Getenv("AILERON_API_URL")
 80→	if apiURL == "" {
 81→		apiURL = "http://localhost:8080"
 82→	}
 83→	apiKey := os.Getenv("AILERON_API_KEY")
 84→
 85→	client := aileron.NewClient(apiURL, aileron.WithAPIKey(apiKey))
 86→	s := &server{client: client}
 87→
 88→	scanner := bufio.NewScanner(os.Stdin)
 89→	// Increase buffer size for large messages.
 90→	scanner.Buffer(make([]byte, 0, 1024*1024), 1024*1024)
 91→
 92→	for scanner.Scan() {
 93→		line := scanner.Bytes()
 94→		if len(line) == 0 {
 95→			continue
 96→		}
 97→
 98→		var req jsonrpcRequest
 99→		if err := json.Unmarshal(line, &req); err != nil {
100→			continue
101→		}
102→
103→		resp := s.handle(req)
104→		if resp != nil {
105→			data, _ := json.Marshal(resp)
106→			fmt.Fprintf(os.Stdout, "%s\n", data)
107→		}
108→	}
109→}
110→
111→func (s *server) handle(req jsonrpcRequest) *jsonrpcResponse {
112→	switch req.Method {
113→	case "initialize":
114→		return &jsonrpcResponse{
115→			JSONRPC: "2.0",
116→			ID:      req.ID,
117→			Result: map[string]any{
118→				"protocolVersion": "2024-11-05",
119→				"capabilities": map[string]any{
120→					"tools": map[string]any{},
121→				},
122→				"serverInfo": map[string]any{
123→					"name":    "aileron",
124→					"version": "0.0.1",
125→				},
126→			},
127→		}
128→
129→	case "notifications/initialized":
130→		return nil // no response for notifications
131→
132→	case "tools/list":
133→		return &jsonrpcResponse{
134→			JSONRPC: "2.0",
135→			ID:      req.ID,
136→			Result: map[string]any{
137→				"tools": s.tools(),
138→			},
139→		}
140→
141→	case "tools/call":
142→		var params callToolParams
143→		if err := json.Unmarshal(req.Params, &params); err != nil {
144→			return errorResponse(req.ID, -32602, "invalid params: "+err.Error())
145→		}
146→		result := s.callTool(params)
147→		return &jsonrpcResponse{
148→			JSONRPC: "2.0",
149→			ID:      req.ID,
150→			Result:  result,
151→		}
152→
153→	case "ping":
154→		return &jsonrpcResponse{
155→			JSONRPC: "2.0",
156→			ID:      req.ID,
157→			Result:  map[string]any{},
158→		}
159→
160→	default:
161→		return errorResponse(req.ID, -32601, "method not found: "+req.Method)
162→	}
163→}
