  2→
  3→import (
  4→	"context"
  5→	"fmt"
  6→	"time"
  7→
  8→	"github.com/ALRubinger/aileron/core/store"
  9→)
 10→
 11→// defaultGrantTTL is how long an execution grant remains active after approval.
 12→const defaultGrantTTL = 5 * time.Minute
 13→
 14→// defaultApprovalTTL is how long an approval request remains pending.
 15→const defaultApprovalTTL = 1 * time.Hour
 16→
 17→// InMemoryOrchestrator implements Orchestrator using in-memory stores.
 18→type InMemoryOrchestrator struct {
 19→	approvals store.ApprovalStore
 20→	newID     func() string // ID generator
 21→}
 22→
 23→// NewInMemoryOrchestrator returns an orchestrator backed by the given store.
 24→// The idGen function should return unique IDs (e.g., UUIDs).
 25→func NewInMemoryOrchestrator(approvals store.ApprovalStore, idGen func() string) *InMemoryOrchestrator {
 26→	return &InMemoryOrchestrator{
 27→		approvals: approvals,
 28→		newID:     idGen,
 29→	}
 30→}
 31→
 32→func (o *InMemoryOrchestrator) Request(ctx context.Context, req ApprovalRequest) (Approval, error) {
 33→	now := time.Now().UTC()
 34→
 35→	expiresAt := now.Add(defaultApprovalTTL)
 36→	if req.ExpiresAt != nil {
 37→		expiresAt = *req.ExpiresAt
 38→	}
 39→
 40→	var actors []ApproverActor
 41→	for _, ref := range req.Approvers {
 42→		actors = append(actors, ApproverActor{
 43→			PrincipalID: ref.PrincipalID,
 44→			DisplayName: ref.DisplayName,
 45→			Role:        ref.Role,
 46→			Status:      ActorStatusPending,
 47→		})
 48→	}
 49→	// Default approver if none specified.
 50→	if len(actors) == 0 {
 51→		actors = []ApproverActor{
 52→			{
 53→				PrincipalID: "default-owner",
 54→				DisplayName: "Workspace Owner",
 55→				Role:        "owner",
 56→				Status:      ActorStatusPending,
 57→			},
 58→		}
 59→	}
 60→
 61→	approval := Approval{
 62→		ApprovalID:     "apr_" + o.newID(),
 63→		IntentID:       req.IntentID,
 64→		WorkspaceID:    req.WorkspaceID,
 65→		Status:         StatusPending,
 66→		Rationale:      req.Rationale,
 67→		Approvers:      actors,
 68→		EditableBounds: req.EditableBounds,
 69→		ExpiresAt:      &expiresAt,
 70→		RequestedAt:    now,
 71→	}
 72→
 73→	// Convert to API type for storage.
 74→	apiApproval := toAPIApproval(approval)
 75→	if err := o.approvals.Create(ctx, apiApproval); err != nil {
 76→		return Approval{}, fmt.Errorf("approval: create: %w", err)
 77→	}
 78→
 79→	return approval, nil
 80→}
 81→
 82→func (o *InMemoryOrchestrator) Get(ctx context.Context, approvalID string) (Approval, error) {
 83→	apiApproval, err := o.approvals.Get(ctx, approvalID)
 84→	if err != nil {
 85→		return Approval{}, err
 86→	}
 87→	return fromAPIApproval(apiApproval), nil
 88→}
 89→
 90→func (o *InMemoryOrchestrator) Approve(ctx context.Context, approvalID string, req ApproveRequest) (Approval, error) {
 91→	apiApproval, err := o.approvals.Get(ctx, approvalID)
 92→	if err != nil {
 93→		return Approval{}, err
 94→	}
 95→
 96→	approval := fromAPIApproval(apiApproval)
 97→	if approval.Status != StatusPending {
 98→		return Approval{}, fmt.Errorf("approval: cannot approve %s in state %s", approvalID, approval.Status)
 99→	}
100→
101→	now := time.Now().UTC()
102→	approval.Status = StatusApproved
103→	approval.ResolvedAt = &now
104→
105→	// Mark all actors as approved.
106→	for i := range approval.Approvers {
107→		approval.Approvers[i].Status = ActorStatusApproved
108→	}
109→
110→	if err := o.approvals.Update(ctx, toAPIApproval(approval)); err != nil {
111→		return Approval{}, fmt.Errorf("approval: update: %w", err)
112→	}
113→
114→	return approval, nil
115→}
116→
117→func (o *InMemoryOrchestrator) Deny(ctx context.Context, approvalID string, req DenyRequest) (Approval, error) {
118→	apiApproval, err := o.approvals.Get(ctx, approvalID)
119→	if err != nil {
120→		return Approval{}, err
121→	}
122→
123→	approval := fromAPIApproval(apiApproval)
124→	if approval.Status != StatusPending {
125→		return Approval{}, fmt.Errorf("approval: cannot deny %s in state %s", approvalID, approval.Status)
126→	}
127→
128→	now := time.Now().UTC()
129→	approval.Status = StatusDenied
130→	approval.ResolvedAt = &now
131→
132→	for i := range approval.Approvers {
133→		approval.Approvers[i].Status = ActorStatusDenied
134→	}
135→
136→	if err := o.approvals.Update(ctx, toAPIApproval(approval)); err != nil {
137→		return Approval{}, fmt.Errorf("approval: update: %w", err)
138→	}
139→
140→	return approval, nil
141→}
142→
143→func (o *InMemoryOrchestrator) Modify(ctx context.Context, approvalID string, req ModifyRequest) (Approval, error) {
144→	apiApproval, err := o.approvals.Get(ctx, approvalID)
145→	if err != nil {
146→		return Approval{}, err
147→	}
148→
149→	approval := fromAPIApproval(apiApproval)
150→	if approval.Status != StatusPending {
151→		return Approval{}, fmt.Errorf("approval: cannot modify %s in state %s", approvalID, approval.Status)
152→	}
153→
154→	now := time.Now().UTC()
155→	approval.Status = StatusModified
156→	approval.ResolvedAt = &now
157→
158→	for i := range approval.Approvers {
159→		approval.Approvers[i].Status = ActorStatusApproved
160→	}
161→
162→	if err := o.approvals.Update(ctx, toAPIApproval(approval)); err != nil {
163→		return Approval{}, fmt.Errorf("approval: update: %w", err)
164→	}
165→
166→	return approval, nil
167→}
168→
169→func (o *InMemoryOrchestrator) List(ctx context.Context, filter ListFilter) ([]Approval, error) {
170→	apiFilter := store.ApprovalFilter{
171→		WorkspaceID: filter.WorkspaceID,
172→		PageSize:    filter.PageSize,
173→		PageToken:   filter.PageToken,
174→	}
175→	if filter.Status != "" {
176→		s := statusToAPIStatus(filter.Status)
177→		apiFilter.Status = &s
178→	}
179→
180→	apiApprovals, err := o.approvals.List(ctx, apiFilter)
181→	if err != nil {
182→		return nil, err
183→	}
184→
185→	var result []Approval
186→	for _, a := range apiApprovals {
187→		result = append(result, fromAPIApproval(a))
188→	}
189→	return result, nil
190→}
