29→func (s *IntentStore) Get(_ context.Context, intentID string) (api.IntentEnvelope, error) {
30→	s.mu.RLock()
31→	defer s.mu.RUnlock()
32→	intent, ok := s.intents[intentID]
33→	if !ok {
34→		return api.IntentEnvelope{}, &store.ErrNotFound{Entity: "intent", ID: intentID}
35→	}
36→	return intent, nil
37→}
