39→func (s *IntentStore) List(_ context.Context, filter store.IntentFilter) ([]api.IntentEnvelope, error) {
40→	s.mu.RLock()
41→	defer s.mu.RUnlock()
42→	var result []api.IntentEnvelope
43→	for _, intent := range s.intents {
44→		if filter.WorkspaceID != "" && intent.WorkspaceId != filter.WorkspaceID {
45→			continue
46→		}
47→		if filter.Status != nil && intent.Status != *filter.Status {
48→			continue
49→		}
50→		if filter.AgentID != "" && intent.Agent.Id != filter.AgentID {
51→			continue
52→		}
53→		result = append(result, intent)
54→	}
55→	return result, nil
56→}
