58→func (s *IntentStore) Update(_ context.Context, intent api.IntentEnvelope) error {
59→	s.mu.Lock()
60→	defer s.mu.Unlock()
61→	if _, ok := s.intents[intent.IntentId]; !ok {
62→		return &store.ErrNotFound{Entity: "intent", ID: intent.IntentId}
63→	}
