11→// GrantStore is a thread-safe in-memory implementation of store.GrantStore.
12→type GrantStore struct {
13→	mu     sync.RWMutex
14→	grants map[string]api.ExecutionGrant
15→}
16→
17→// NewGrantStore returns an empty in-memory grant store.
18→func NewGrantStore() *GrantStore {
19→	return &GrantStore{grants: make(map[string]api.ExecutionGrant)}
20→}
21→
22→func (s *GrantStore) Create(_ context.Context, grant api.ExecutionGrant) error {
23→	s.mu.Lock()
24→	defer s.mu.Unlock()
25→	s.grants[grant.GrantId] = grant
26→	return nil
27→}
28→
29→func (s *GrantStore) Get(_ context.Context, grantID string) (api.ExecutionGrant, error) {
30→	s.mu.RLock()
31→	defer s.mu.RUnlock()
32→	g, ok := s.grants[grantID]
33→	if !ok {
34→		return api.ExecutionGrant{}, &store.ErrNotFound{Entity: "grant", ID: grantID}
35→	}
36→	return g, nil
37→}
38→
39→func (s *GrantStore) Update(_ context.Context, grant api.ExecutionGrant) error {
40→	s.mu.Lock()
41→	defer s.mu.Unlock()
42→	if _, ok := s.grants[grant.GrantId]; !ok {
43→		return &store.ErrNotFound{Entity: "grant", ID: grant.GrantId}
44→	}
45→	s.grants[grant.GrantId] = grant
46→	return nil
47→}
